parameters.jsCode:
const raw = $json.text || "";

function fb(reason) {
  return [{
    json: {
      leaf: "🛡️ Inne",
      summary: reason,
      icon: "⚠️",
      sections: [
        { title: "Zakres funkcjonalny", content: "Brak - błąd modelu" },
        { title: "Zastosowanie w automatyzacji", content: "Brak - błąd modelu" },
        { title: "Uwagi integracyjne", content: reason }
      ],
      github: { name: "Błąd", url: "" }
    }
  }];
}

// Wyciągnij JSON między klamrami
const jsonMatch = raw.match(/\{[\s\S]*\}/);
if (!jsonMatch) return fb("Pusta odpowiedź LLM");

let cleaned = jsonMatch[0];

// === KLUCZOWE NAPRAWY ===

// 1. Usuń literalne \n wewnątrz wartości stringów (model wstawia je mimo zakazu)
// Zamień \n na spację tylko wewnątrz cudzysłowów
cleaned = cleaned.replace(/"((?:[^"\\]|\\.)*)"/g, (match, inner) => {
  const fixed = inner
    .replace(/\\n/g, ' ')      // escaped \n -> spacja
    .replace(/\n/g, ' ')       // prawdziwy newline -> spacja
    .replace(/\r/g, '')        // carriage return
    .replace(/\t/g, ' ')       // tab -> spacja
    .replace(/\s+/g, ' ')      // wielokrotne spacje -> jedna
    .replace(/"/g, "'")        // cudzysłowy wewnątrz -> apostrofy (dodatkowe zabezpieczenie)
    .trim();
  return `"${fixed}"`;
});

// 2. Usuń trailing commas przed } lub ]
cleaned = cleaned.replace(/,\s*([}\]])/g, '$1');

try {
  if (!cleaned) return fb("Pusta odpowiedź LLM");
  const o = JSON.parse(cleaned);

  if (!o.leaf) return fb("Brak leaf");
  if (!o.summary) return fb("Brak summary");
  if (!Array.isArray(o.sections)) return fb("Sections nie jest tablicą");

  return [{ json: o }];
} catch (e) {
  return fb(`Parse error: ${e.message}`);
}

const resolveData = $node["Resolve Notion Block"].json;
const incomingUrl = resolveData.html_url;

const blocks = $input.all();

function extractUrl(block) {
  const rt = block.json?.toggle?.text || [];
  for (const t of rt) {
    if (t.text?.link?.url) return t.text.link.url;
  }
  return null;
}

let exists = false;

for (const b of blocks) {
  const url = extractUrl(b);
  if (url === incomingUrl) {
    exists = true;
    break;
  }
}

return [
  {
    json: {
      ...resolveData,   // ← kluczowe
      exists,
      scanned: blocks.length
    }
  }
];
